import { NextResponse } from "next/server";
import { getSupabaseAdmin } from "../../../../lib/supabaseAdmin";
export async function POST(req){const body=await req.json();const supabase=getSupabaseAdmin();const vendor=body.vendor||{};if(!supabase)return NextResponse.json({ok:false,mode:"safe-placeholder",message:"Vendor added locally. Add Supabase env vars to save permanently.",vendor});const {error}=await supabase.from("vendors").insert({business_name:vendor.name||"",category:vendor.category||"",location:vendor.city||"",price_range:vendor.price||"",plan:vendor.plan||"starter",verified:false});if(error)return NextResponse.json({ok:false,message:error.message},{status:500});return NextResponse.json({ok:true,message:"Vendor saved to Supabase."})}
